require\('./src/index'\);
const { run } = require\('./src/pipeline'\);

const OPTS_CLASSIFY = { categories: ['add','balance','summary','ledger','delete'] };
const OPTS_EXTRACT  = { fields: ['type','amount','party','category'] };

async function classify\(text\) {
  const r = await run\({ provider:'nvidia', task:'classification', input:{ text }, options: OPTS_CLASSIFY }\);
  return r.ok ? r.output : { label:'ERROR', error: r.error };
}

async function extract\(text\) {
  const r = await run\({ provider:'nvidia', task:'extraction', input:{ text }, options: OPTS_EXTRACT }\);
  return r.ok ? r.output.fields : { ERROR: r.error };
}

async function testAdd\(msg\) {
  const c = await classify\(msg\);
  const label = c.label;
  if \(label !== 'add'\) return { classify: label, extract: 'SKIPPED' };
  const e = await extract\(msg\);
  return { classify: label, ...e };
}

async function testCmd\(msg\) {
  const c = await classify\(msg\);
  return { classify: c.label, confidence: c.confidence?.toFixed\(2\) };
}

